    // Using an array of arrays of boolean arrays for fixed size optimization.
    // Initialize DP table: m rows, n columns, R_MAX possible XOR sums.
    val dp = Array.ofDim[Boolean](m) { Array.ofDim[Boolean](n) { Array.fill(R_MAX)(false) } }

    // Base Case (0, 0)
